import shioaji as _sj

_EXPORTS = {
    "ShioajiError": "ShioajiError",
    "TokenError": "TokenError",
    "SystemMaintenance": "SystemMaintenance",
    "ShioajiTimeoutError": "ShioajiTimeoutError",
    "AccountNotSignError": "AccountNotSignError",
    "AccountNotProvideError": "AccountNotProvideError",
    "CaError": "CaError",
    "AuthError": "AuthError",
    "ServerError": "ServerError",
    "ValidationError": "ValidationError",
    "BadRequestError": "BadRequestError",
}

def __getattr__(name):
    if name in _EXPORTS:
        import warnings
        warnings.warn(
            f"shioaji.error.{name} is deprecated, use sj.{_EXPORTS[name]}",
            DeprecationWarning,
            stacklevel=2,
        )
        return getattr(_sj, _EXPORTS[name])
    raise AttributeError(f"module 'shioaji.error' has no attribute {name!r}")
